import { StudioLayouts } from '.';
import type { StudioLayoutBasePropsConfig } from './StudioBaseSchema';
export interface StudioLayoutIconConfig extends StudioLayoutBasePropsConfig {
    /**
     * Type of the layout component.
     */
    type: `${StudioLayouts.icon}`;
    /**
     * The icon to display. Can be an IconNames enum value or an SVG path string.
     * @example "chevronDown"
     */
    icon?: string;
    /**
     * The size of the icon.
     * @example "16px"
     */
    size?: string | number;
    /**
     * Rotation angle in degrees.
     * @example 90
     */
    rotate?: number;
    /**
     * Whether to flip the icon vertically.
     */
    vertical?: boolean;
    /**
     * Whether to flip the icon horizontally.
     */
    horizontal?: boolean;
}
